// IPC Input Injection
// Injects mouse and keyboard events into the application
// Only compiled in debug builds (GITSMARTER_DEBUG)

#ifdef GITSMARTER_DEBUG

#include "../include/ipc.h"
#include "../include/app.h"

// Forward declarations for globals in platform.cpp
extern HWND g_main_window;

// ============================================================================
// Mouse Input Injection
// ============================================================================

void ipc_inject_mouse_move(int x, int y) {
    if (!g_main_window) return;

    LPARAM lParam = MAKELPARAM(x, y);
    PostMessageW(g_main_window, WM_MOUSEMOVE, 0, lParam);
}

void ipc_inject_mouse_down(int x, int y, int button) {
    if (!g_main_window) return;

    LPARAM lParam = MAKELPARAM(x, y);
    UINT msg = 0;
    WPARAM wParam = 0;

    switch (button) {
        case 0:  // Left button
            msg = WM_LBUTTONDOWN;
            wParam = MK_LBUTTON;
            break;
        case 1:  // Right button
            msg = WM_RBUTTONDOWN;
            wParam = MK_RBUTTON;
            break;
        case 2:  // Middle button
            msg = WM_MBUTTONDOWN;
            wParam = MK_MBUTTON;
            break;
        default:
            return;
    }

    PostMessageW(g_main_window, msg, wParam, lParam);
}

void ipc_inject_mouse_up(int x, int y, int button) {
    if (!g_main_window) return;

    LPARAM lParam = MAKELPARAM(x, y);
    UINT msg = 0;

    switch (button) {
        case 0:  // Left button
            msg = WM_LBUTTONUP;
            break;
        case 1:  // Right button
            msg = WM_RBUTTONUP;
            break;
        case 2:  // Middle button
            msg = WM_MBUTTONUP;
            break;
        default:
            return;
    }

    PostMessageW(g_main_window, msg, 0, lParam);
}

void ipc_inject_mouse_wheel(int x, int y, float delta) {
    if (!g_main_window) return;

    // WM_MOUSEWHEEL uses screen coordinates
    POINT pt = { x, y };
    ClientToScreen(g_main_window, &pt);

    // Wheel delta is in units of WHEEL_DELTA (120)
    short wheel_delta = (short)(delta * WHEEL_DELTA);
    WPARAM wParam = MAKEWPARAM(0, wheel_delta);
    LPARAM lParam = MAKELPARAM(pt.x, pt.y);

    PostMessageW(g_main_window, WM_MOUSEWHEEL, wParam, lParam);
}

// ============================================================================
// Keyboard Input Injection
// ============================================================================

void ipc_inject_key_down(int vk, bool ctrl, bool shift, bool alt) {
    if (!g_main_window) return;

    // Simulate modifier key states by posting modifier key messages first
    // Note: This is a simplified approach. For full modifier support,
    // we'd need to track key state or use SendInput()

    if (ctrl) {
        PostMessageW(g_main_window, WM_KEYDOWN, VK_CONTROL, 0);
    }
    if (shift) {
        PostMessageW(g_main_window, WM_KEYDOWN, VK_SHIFT, 0);
    }
    if (alt) {
        PostMessageW(g_main_window, WM_KEYDOWN, VK_MENU, 0);
    }

    // Build lParam with scan code
    UINT scanCode = MapVirtualKeyW(vk, MAPVK_VK_TO_VSC);
    LPARAM lParam = 1 | (scanCode << 16);

    PostMessageW(g_main_window, WM_KEYDOWN, vk, lParam);
}

void ipc_inject_key_up(int vk) {
    if (!g_main_window) return;

    UINT scanCode = MapVirtualKeyW(vk, MAPVK_VK_TO_VSC);
    LPARAM lParam = 1 | (scanCode << 16) | (1 << 30) | (1 << 31);  // Previous state and transition flags

    PostMessageW(g_main_window, WM_KEYUP, vk, lParam);

    // Release any modifier keys
    PostMessageW(g_main_window, WM_KEYUP, VK_CONTROL, 0);
    PostMessageW(g_main_window, WM_KEYUP, VK_SHIFT, 0);
    PostMessageW(g_main_window, WM_KEYUP, VK_MENU, 0);
}

// ============================================================================
// Character Input Injection
// ============================================================================

void ipc_inject_char(wchar_t ch) {
    if (!g_main_window) return;

    PostMessageW(g_main_window, WM_CHAR, ch, 0);
}

// ============================================================================
// Window Info Query
// ============================================================================

void ipc_get_window_info(IpcWindowInfo* info) {
    if (!info) return;

    memset(info, 0, sizeof(IpcWindowInfo));

    if (!g_main_window) return;

    // Get window dimensions
    RECT rc;
    if (GetClientRect(g_main_window, &rc)) {
        info->width = rc.right - rc.left;
        info->height = rc.bottom - rc.top;
    }

    // Get window title
    GetWindowTextW(g_main_window, info->title, _countof(info->title));

    // Check if window has focus
    info->focused = (GetForegroundWindow() == g_main_window);

    // Check if window is visible
    info->visible = IsWindowVisible(g_main_window) != FALSE;
}

#endif // GITSMARTER_DEBUG
